public class FactoryMethod {
    abstract static class Button { abstract void render(); }
    static class WinButton extends Button { void render() { System.out.println("Windows button"); } }
    static class MacButton extends Button { void render() { System.out.println("Mac button"); } }
    abstract static class Dialog { abstract Button createButton(); void show() { createButton().render(); } }
    static class WinDialog extends Dialog { Button createButton() { return new WinButton(); } }
    static class MacDialog extends Dialog { Button createButton() { return new MacButton(); } }
    public static void main(String[] args) {
        Dialog d1 = new WinDialog();
        Dialog d2 = new MacDialog();
        d1.show();
        d2.show();
    }
}
